import array as arr

class RangingMeasurements:
    """A structure to hold ranging measurements.

    Parameters
    ----------
    distance : float[]
        The distances in metres.
    distance_sigma : float[]
        Estimates of the standard deviation in the current distance measurement.
    heading : float[]
        The headings in radians (will be zero for 1D ranging sensors).
    quality : int[]
        Indications of the quality of the measurement (0 to 100%).
    length : int
        The number of valid measurements in each array.

    Examples
    --------
    Create a holder for ranging measurements.

    >>> from quanser.devices.types import RangingMeasurements
    >>> measurement = RangingMeasurements(num_measurements)

    Create a ranging measurement holder containing values.

    >>> from quanser.devices.types import RangingMeasurements
    >>> measurement = RangingMeasurements(720, 10.0, 0.2, 0.0, 50)

    """
    def __init__(self, num_measurements = 0, distance = 0.0, distance_sigma = 0.0, heading = 0.0, quality = 0):
        """Creates a RangingMeasurements structure, allocating arrays initialized to the given default values
        for each field in the structure.

        Parameters
        ----------
        num_measurements: int
            The number of elements to allocate in the arrays for each field of the structure.
        distance : float
            The distance in metres to which to initialize the array elements of the distance field.
             The default value is 0.0.
        distance_sigma : float
            The estimate of the standard deviation in the current distance measurement to which to initialize
            the array elements of the distance_sigma field. The default value is 0.0.
        heading : float
            The heading in radians (will be zero for 1D ranging sensors) to which to initialize
            the array elements of the heading field. The default value is 0.0.
        quality : int
            The indication of the quality of the measurement (0 to 100%) to which to initialize
            the array elements of the heading field. The default value is 0.

        Examples
        --------
        Create a holder for num_measurements ranging measurements.

        >>> from quanser.devices.types import RangingMeasurements
        >>> num_measurements = 7200
        >>> measurements = RangingMeasurements(num_measurements)

        Create a ranging measurement holder containing non-zero values.

        >>> from quanser.devices.types import RangingMeasurements
        >>> num_measurements = 7200
        >>> measurements = RangingMeasurements(num_measurements, 10.0, 0.2, 0.0, 50)

        Create an empty holder for ranging measurements and then allocate numpy
        arrays for each of the fields of interest.

        >>> from quanser.devices.types import RangingMeasurements
        >>> import numpy as np
        >>> measurement = RangingMeasurements()
        >>> num_measurements = 7200
        >>> measurement.distance = np.array([0] * num_measurements, dtype=np.single)
        >>> measurement.heading = np.array([0] * num_measurements, dtype=np.single)

        """
        if (num_measurements == 0):
            self.distance = None
            self.distance_sigma = None
            self.heading = None
            self.quality = None
        else:
            self.distance = arr.array('f', [distance] * num_measurements)
            self.distance_sigma = arr.array('f', [distance_sigma] * num_measurements)
            self.heading = arr.array('f', [heading] * num_measurements)
            self.quality = arr.array('i', [quality] * num_measurements)

        self.length = 0

class VRPNAnalogMeasurements:
    """A structure to hold VRPN analog measurements.

    Attributes
    ----------
    device : int
        Index of the analog device that this measurement represents.
    channel : int
        Index of the channel of the `device` that this measurement represents.
    new : boolean
        Indicates whether this measurement contains new data.
    value : float
        Represents the analog value of the `channel`.
    
    Examples
    --------
    Create a holder for analog reading measurements.

    >>> from quanser.common.utilities import count_list_elements
    >>> from quanser.devices import VRPNClient, VRPNAnalogMeasurements
    >>> analog_names = ['Mouse0']
    >>> analog_num_channels = arr.array('I', [2])
    >>> analog_channels_to_read = [[0, 1]]
    >>> num_analog_channels = count_list_elements(analog_channels_to_read)
    >>> analog_measurements = [VRPNAnalogMeasurements() for _ in range(num_analog_channels)]
    >>> vrpn_client = VRPNClient()
    >>> vrpn_client.open("localhost:3883",
                  analog_names, analog_num_channels,
                  None, None,
                  None, None,
                  None, None)
    >>> vrpn_client.initialize(analog_channels_to_read, None, None, None)
    >>> vrpn_client.read(analog_measurements, None, None, None, False)
    >>> vrpn_client.close()
    """
    def __init__(self):
        """Creates a VRPNAnalogMeasurements structure.
        """

        self.device = [0]
        self.channel = [0]
        self.new = [False]
        self.value = [0.0]

class VRPNButtonMeasurements:
    """A structure to hold VRPN button measurements.

    Attributes
    ----------
    device : int
        Index of the button device that this measurement represents.
    button : int
        Index of the button of the `device` that this measurement represents.
    new : boolean
        Indicates whether this measurement contains new data.
    value : boolean
        Represents the value of the `button`.
    
    Examples
    --------
    Create a holder for button reading measurements.

    >>> from quanser.common.utilities import count_list_elements
    >>> from quanser.devices import VRPNClient, VRPNButtonMeasurements
    >>> button_names = ['Mouse0']
    >>> button_num_buttons = arr.array('I', [3])
    >>> button_buttons_to_read = [[0, 1, 2]]
    >>> num_button_buttons = count_list_elements(button_buttons_to_read)
    >>> button_measurements = [VRPNButtonMeasurements() for _ in range(num_button_buttons)]
    >>> vrpn_client = VRPNClient()
    >>> vrpn_client.open("localhost:3883",
                  None, None,
                  button_names, button_num_buttons,
                  None, None,
                  None, None)
    >>> vrpn_client.initialize(None, button_buttons_to_read, None, None)
    >>> vrpn_client.read(None, button_measurements, None, None, False)
    >>> vrpn_client.close()
    """
    def __init__(self):
        """Creates a VRPNButtonMeasurements structure.
        """

        self.device = [0]
        self.button = [0]
        self.new = [False]
        self.value = [False]

